sql:
SELECT COUNT(DISTINCT country_id)
FROM happiness_scores
WHERE score > 7.0;

SELECT ip_address
FROM access_logs
WHERE access_date BETWEEN '2020-01-01' AND '2023-12-31';

external_knowledge:
- 'Contentment' here refers to a combined measure of happiness and economic prosperity;
- The ATAN2 function is used to combine two averages (happiness and economic indicators) into a single measure;
- Economic well-being is represented by GDP per capita.

sql:
SELECT DISTINCT region 
FROM countries 
WHERE capital = 'Tirana';

SELECT AVG(overall_rank) AS average_overall_rank
FROM happiness_scores
WHERE year = 2023;
